import{_ as a,o as n,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"175. Unplanned Absences","description":"","frontmatter":{"title":"175. Unplanned Absences","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/175-unplanned-absences.md","filePath":"ebas/mental-health/support-services/preliminary/175-unplanned-absences.md"}'),r={name:"ebas/mental-health/support-services/preliminary/175-unplanned-absences.md"};function l(o,e,i,p,c,m){return n(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_175-unplanned-absences" tabindex="-1">175. Unplanned Absences <a class="header-anchor" href="#_175-unplanned-absences" aria-label="Permalink to &quot;175. Unplanned Absences&quot;">​</a></h1><p><strong>175.1</strong> The Employer agrees to replace staff on planned or unplanned absences, where practicable.</p><p><strong>175.2</strong> The Employer will endeavour to maximise the use of permanent, full-time and part- time Employees to replace staff on planned and unplanned absences.</p><p><strong>175.3</strong> The engagement of casual Employees will be in accordance with the spirit and intent of <a href="/eba/ebas/mental-health/common-terms/employment-types/25-modes-of-employment.html">clause 25.4</a> of this Agreement (casual employment).</p><p><strong>175.4</strong> Where additional shifts are required to replace unplanned absences, the Employer will give preference to existing part-time Employees to work such shifts. If this is not possible, the Employer may use casual Employees as an interim measure, in classifications where casuals are available.</p><p><strong>175.5</strong> Agency staff should only be used for unexpected absences, such as sick leave, where the Employer is unable to replace the Employee with either part-time or casual Employees.</p><p><strong>175.6</strong> In the event that particular staffing issues are identified at individual health care facilities the Employers agree to consult with Employees and the Union in relation to any matters raised, under the existing consultative arrangements.</p>',7)])])}const u=a(r,[["render",l]]);export{d as __pageData,u as default};
